-- ============================================================
-- Migration 002: ML Prediction Tables
-- Stores workload forecasts and burnout scores generated by
-- the RandomForest / GradientBoosting models in the
-- classification-service.
-- ============================================================

-- Workload Predictions
-- One row per predicted working day per user (refreshed on each sync).
CREATE TABLE IF NOT EXISTS workload_predictions (
    id              UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id         UUID        NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    generated_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    predicted_date  DATE        NOT NULL,
    predicted_minutes INTEGER   NOT NULL,
    predicted_hours DECIMAL(5,2),
    confidence      DECIMAL(4,3),
    load_level      VARCHAR(20) CHECK (load_level IN ('light','moderate','high','critical')),
    trend           VARCHAR(20) CHECK (trend IN ('increasing','stable','decreasing')),
    model_version   VARCHAR(50) DEFAULT 'rf-workload-v1.0',
    created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_workload_predictions_user_date
    ON workload_predictions(user_id, predicted_date);

-- Burnout Scores
-- One row per user per day (upserted on each sync).
CREATE TABLE IF NOT EXISTS burnout_scores (
    id                   UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id              UUID        NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    score_date           DATE        NOT NULL DEFAULT CURRENT_DATE,
    score                DECIMAL(5,2) NOT NULL,
    level                VARCHAR(20) NOT NULL
                             CHECK (level IN ('none','low','medium','high','critical')),
    trend                VARCHAR(20) CHECK (trend IN ('improving','stable','worsening')),
    contributing_factors JSONB       NOT NULL DEFAULT '[]',
    confidence           DECIMAL(4,3),
    probabilities        JSONB       NOT NULL DEFAULT '{}',
    metrics_summary      JSONB       NOT NULL DEFAULT '{}',
    model_version        VARCHAR(50) DEFAULT 'gbm-burnout-v1.0',
    created_at           TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at           TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    UNIQUE(user_id, score_date)
);

CREATE INDEX IF NOT EXISTS idx_burnout_scores_user_date
    ON burnout_scores(user_id, score_date DESC);
